import { Component, signal } from '@angular/core';
import {
  CardComponent,
  CardHeaderComponent,
  CardTitleComponent,
  CardDescriptionComponent,
} from '../card.component';

@Component({
  selector: 'demo-card-clickable',
  standalone: true,
  imports: [
    CardComponent,
    CardHeaderComponent,
    CardTitleComponent,
    CardDescriptionComponent,
  ],
  template: `
    <div class="flex flex-col gap-3 w-80">
      <p class="text-sm text-muted-foreground">
        Selecionado: <strong>{{ selected() ?? 'nenhum' }}</strong>
      </p>
      @for (plan of plans; track plan.id) {
        <n-card
          [nClickable]="true"
          [nSelected]="selected() === plan.id"
          (nClick)="selected.set(plan.id)"
          nClass="w-full"
        >
          <n-card-header nClass="pb-0">
            <n-card-title>{{ plan.name }}</n-card-title>
            <n-card-description>{{ plan.description }}</n-card-description>
          </n-card-header>
        </n-card>
      }
    </div>
  `,
})
export class CardDemoClickable {
  readonly selected = signal<string | null>(null);

  readonly plans = [
    { id: 'free',       name: 'Gratuito',   description: 'Para uso pessoal e projetos pequenos' },
    { id: 'pro',        name: 'Pro',        description: 'Para times e projetos em crescimento' },
    { id: 'enterprise', name: 'Enterprise', description: 'Para grandes organizações' },
  ];
}

import { Component, OnInit, signal } from '@angular/core';
import { ButtonComponent } from '../../button';
import {
  CardComponent,
  CardHeaderComponent,
  CardTitleComponent,
  CardDescriptionComponent,
  CardContentComponent,
  CardFooterComponent,
} from '../card.component';

@Component({
  selector: 'demo-card-loading',
  standalone: true,
  imports: [
    CardComponent,
    CardHeaderComponent,
    CardTitleComponent,
    CardDescriptionComponent,
    CardContentComponent,
    CardFooterComponent,
    ButtonComponent,
  ],
  template: `
    <n-card [nLoading]="loading()" nClass="w-80">
      <n-card-header>
        <n-card-title>Relatório Mensal</n-card-title>
        <n-card-description>Dados de maio de 2026</n-card-description>
      </n-card-header>
      <n-card-content>
        <p class="text-sm text-muted-foreground">
          R$ 12.430,00 em receita total este mês.
        </p>
      </n-card-content>
      <n-card-footer>
        <button n-button nVariant="outline" nSize="sm" (click)="reload()">
          {{ loading() ? 'Carregando...' : 'Recarregar' }}
        </button>
      </n-card-footer>
    </n-card>
  `,
})
export class CardDemoLoading implements OnInit {
  readonly loading = signal(true);

  private _timer: ReturnType<typeof setTimeout> | null = null;

  ngOnInit(): void {
    this._timer = setTimeout(() => this.loading.set(false), 2000);
  }

  reload(): void {
    if (this._timer) clearTimeout(this._timer);
    this.loading.set(true);
    this._timer = setTimeout(() => this.loading.set(false), 2000);
  }
}

import { Component } from '@angular/core';
import {
  CardComponent,
  CardHeaderComponent,
  CardTitleComponent,
  CardDescriptionComponent,
  CardContentComponent,
} from '../card.component';

@Component({
  selector: 'demo-card-variants',
  standalone: true,
  imports: [
    CardComponent,
    CardHeaderComponent,
    CardTitleComponent,
    CardDescriptionComponent,
    CardContentComponent,
  ],
  template: `
    <div class="grid grid-cols-2 gap-4 w-full max-w-2xl">
      @for (variant of variants; track variant.value) {
        <n-card [nVariant]="variant.value" nClass="w-full">
          <n-card-header>
            <n-card-title>{{ variant.name }}</n-card-title>
            <n-card-description>nVariant="{{ variant.value }}"</n-card-description>
          </n-card-header>
          <n-card-content>
            <p class="text-sm text-muted-foreground">
              Exemplo do estilo {{ variant.name.toLowerCase() }}.
            </p>
          </n-card-content>
        </n-card>
      }
    </div>
  `,
})
export class CardDemoVariants {
  readonly variants = [
    { name: 'Default',  value: 'default'  as const },
    { name: 'Elevated', value: 'elevated' as const },
    { name: 'Filled',   value: 'filled'   as const },
    { name: 'Ghost',    value: 'ghost'    as const },
  ];
}
